// Tiny argv parser used by the CLI.
// Supports `--flag value`, `--flag=value`, `--bool`, and positional args.
// No third-party deps; intentionally minimal.

export interface ParsedArgs {
  command: string;
  positional: string[];
  options: Record<string, string | boolean>;
}

// A tiny CLI front-end to the kvstore. Not the focus of the example —
// it exists so the store has a non-trivial caller that exercises imports
// across the package.
//
// Commands:
//   put <key> <value> [--ttl <ms>] [--tag <name>]
//   get <key>
//   delete <key>
//   list
//   stats
//   save <path>
//   load <path>

import { FlagParseError, type ParsedArgs, numberOption, parseArgs } from "./flags.ts";

// Process entry point. Wires `process.argv` to the CLI runner and
// exits with the appropriate status code. Kept separate from `cli.ts`
// so the CLI logic is unit-testable without touching `process`.

import { runCli } from "./cli.ts";

// `import.meta.url` lets us check whether this module is being run directly.
// When imported (e.g. by tests), we don't auto-run.
const isDirectRun = process.argv[1] !== undefined &&
  import.meta.url === `file://${process.argv[1]}`;

export const systemClock: Clock = {
  now: () => Date.now(),
};

export interface AuditEntry {
  kind: AuditKind;
  subjectId: string;
  ts: number;
}

async function main(): Promise<void> {
  const store = new KvStore<string>({ maxEntries: 4096 });
  const code = await runCli({
    argv: process.argv.slice(2),
    out: (line) => process.stdout.write(`${line}\n`),
    err: (line) => process.stderr.write(`${line}\n`),
    store,
  });
  process.exit(code);
}

/** A stored entry. The store owns its lifecycle; consumers see read-only copies. */
export interface Entry<V> {
  readonly key: string;
  readonly value: V;
  readonly insertedAt: Millis;
  readonly expiresAt: Millis | null;
  readonly tags: readonly string[];
  readonly hits: number;
}

/** Load a snapshot from disk and restore it into the given store. */
export async function loadFromFile<V>(
  store: KvStore<V>,
  path: string,
): Promise<void> {
  const raw = await readFile(path, "utf8");
  const parsed = JSON.parse(raw) as SnapshotShape<V>;
  if (parsed.version !== 1) {
    throw new Error(
      `unsupported snapshot version ${parsed.version} at ${path} (expected 1)`,
    );
  }
  store.restore(parsed);
}

