function handleGet(env: CliEnv, args: ParsedArgs): number {
  const [key] = args.positional;
  if (!key) {
    env.err("get requires <key>");
    return 2;
  }
  const value = env.store.get(key);
  if (value === undefined) {
    env.err(`miss: ${key}`);
    return 1;
  }
  env.out(value);
  return 0;
}

