// Library entrypoint. Re-exports the public surface so consumers can
// `import { KvStore } from "@strata-examples/medium-kvstore"` without
// reaching into individual files.

export { KvStore, type StoreOptions } from "./store.ts";

/** Save the store's current snapshot to disk. */
export async function saveToFile<V>(
  store: KvStore<V>,
  path: string,
): Promise<void> {
  const snapshot = store.snapshot();
  const serialized = JSON.stringify(snapshot, null, 2);

  await mkdir(dirname(path), { recursive: true });
  const tempPath = `${path}.tmp-${process.pid}-${Date.now()}`;
  await writeFile(tempPath, serialized, "utf8");
  await rename(tempPath, path);
}

export function parseArgs(argv: readonly string[]): ParsedArgs {
  if (argv.length === 0) {
    throw new FlagParseError("expected a command (run with --help for usage)");
  }

  const [command, ...rest] = argv;
  const positional: string[] = [];
  const options: Record<string, string | boolean> = {};

  for (let i = 0; i < rest.length; i++) {
    const token = rest[i]!;
    if (!token.startsWith("--")) {
      positional.push(token);
      continue;
    }
    const body = token.slice(2);
    const eqIndex = body.indexOf("=");
    if (eqIndex >= 0) {
      const name = body.slice(0, eqIndex);
      const value = body.slice(eqIndex + 1);
      options[name] = value;
      continue;
    }
    // Bare flag — look ahead for a value, otherwise treat as boolean.
    const next = rest[i + 1];
    if (next === undefined || next.startsWith("--")) {
      options[body] = true;
    } else {
      options[body] = next;
      i++;
    }
  }

  return { command: command!, positional, options };
}

